#!/bin/bash
pkill anvil
anvil &
sleep 2

PRIVATE_KEY=0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80
RPC=http://localhost:8545

# Deploy TSender
cast send --private-key $PRIVATE_KEY --rpc-url $RPC --create 

# Deploy Mock Token
cast send --private-key $PRIVATE_KEY --rpc-url $RPC --create 

# Mint tokens
cast send --private-key $PRIVATE_KEY --rpc-url $RPC \
  0xe7f1725E7734CE288F8367e1Bb143E90bb3F0512 \
  "mint(uint256)" 100000000000000000000

echo "Done! Contracts deployed and tokens minted."